-- -----------------------------------------------------------------------
-- E-Digital — Import des pages WP (Option A : templates PHP fidèles).
-- Généré automatiquement par wp-theme-edigital/sql/build-theme.py
-- Chaque page pointe vers un template dans wp-content/themes/edigital/templates/.
-- Idempotent : re-exécuter le fichier supprime puis recrée les pages.
-- -----------------------------------------------------------------------

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- Nettoyage préalable des pages E-Digital déjà présentes.
DELETE pm FROM wp_postmeta pm INNER JOIN wp_posts p ON p.ID = pm.post_id WHERE p.post_name IN ('accueil', 'services', 'service-creation-web', 'service-mobile-native', 'service-app-metier', 'service-branding', 'service-visibilite-seo', 'service-visibilite-google-ads', 'service-maintenance', 'nos-technologies', 'nos-projets', 'blog', 'contact', 'accueil-menu-item', 'services-menu-item', 'service-creation-web-menu-item', 'service-mobile-native-menu-item', 'service-app-metier-menu-item', 'service-branding-menu-item', 'service-visibilite-seo-menu-item', 'service-visibilite-google-ads-menu-item', 'service-maintenance-menu-item', 'nos-technologies-menu-item', 'nos-projets-menu-item', 'blog-menu-item', 'contact-menu-item') AND p.post_type IN ('page','nav_menu_item');
DELETE FROM wp_posts WHERE post_name IN ('accueil', 'services', 'service-creation-web', 'service-mobile-native', 'service-app-metier', 'service-branding', 'service-visibilite-seo', 'service-visibilite-google-ads', 'service-maintenance', 'nos-technologies', 'nos-projets', 'blog', 'contact', 'accueil-menu-item', 'services-menu-item', 'service-creation-web-menu-item', 'service-mobile-native-menu-item', 'service-app-metier-menu-item', 'service-branding-menu-item', 'service-visibilite-seo-menu-item', 'service-visibilite-google-ads-menu-item', 'service-maintenance-menu-item', 'nos-technologies-menu-item', 'nos-projets-menu-item', 'blog-menu-item', 'contact-menu-item') AND post_type IN ('page','nav_menu_item');

-- Nettoyage du menu principal.
DELETE tr FROM wp_term_relationships tr INNER JOIN wp_term_taxonomy tt ON tt.term_taxonomy_id = tr.term_taxonomy_id INNER JOIN wp_terms t ON t.term_id = tt.term_id WHERE tt.taxonomy = 'nav_menu' AND t.slug = 'edigital-primary';
DELETE tt FROM wp_term_taxonomy tt INNER JOIN wp_terms t ON t.term_id = tt.term_id WHERE tt.taxonomy = 'nav_menu' AND t.slug = 'edigital-primary';
DELETE FROM wp_terms WHERE slug = 'edigital-primary';

-- Pages (contenu minimal + template PHP assigné).


-- Menu principal E-Digital.
UPDATE wp_term_taxonomy SET count = (SELECT COUNT(*) FROM wp_term_relationships WHERE term_taxonomy_id = 9000) WHERE term_taxonomy_id = 9000;


SET FOREIGN_KEY_CHECKS = 1;

